CREATE OR REPLACE FUNCTION pg_temp.broki_export_legacy_raw()
RETURNS TABLE (
  source_schema text,
  source_table text,
  total_rows bigint,
  batch_offset integer,
  items jsonb
)
LANGUAGE plpgsql
AS $$
DECLARE
  tbl text;
  tbl_list text[] := ARRAY[
    'personal',
    'inventario',
    'incidencias',
    'grupo_trabajo',
    'tareas',
    'aviones',
    'tooling',
    'tool_control',
    'furgonetas',
    'gse',
    'registro_comunicaciones',
    'n8n_chat_histories',
    'no_existe_telefono'
  ];
  reg oid;
  cnt bigint;
  off integer;
  bs integer := 1000;
BEGIN
  FOREACH tbl IN ARRAY tbl_list LOOP
    reg := to_regclass(format('pro.%I', tbl));
    IF reg IS NULL THEN
      RAISE NOTICE 'broki export: skipping missing table pro.%', tbl;
      CONTINUE;
    END IF;

    EXECUTE format('SELECT count(*)::bigint FROM %I.%I', 'pro', tbl) INTO cnt;

    off := 0;
    WHILE off < cnt LOOP
      source_schema := 'pro';
      source_table := tbl;
      total_rows := cnt;
      batch_offset := off;

      EXECUTE format(
        $q$
        SELECT coalesce(jsonb_agg(row_data), '[]'::jsonb)
        FROM (
          SELECT to_jsonb(t) AS row_data
          FROM %I.%I t
          ORDER BY COALESCE(
            to_jsonb(t)->>'id',
            to_jsonb(t)->>'identificador',
            to_jsonb(t)->>'brk',
            to_jsonb(t)->>'codigo',
            to_jsonb(t)->>'id_incidencia',
            to_jsonb(t)->>'external_id',
            md5(to_jsonb(t)::text)
          )
          LIMIT %s OFFSET %s
        ) sub
        $q$,
        'pro', tbl, bs, off
      ) INTO items;

      IF items IS NOT NULL AND jsonb_array_length(items) > 0 THEN
        RETURN NEXT;
      END IF;

      off := off + bs;
    END LOOP;
  END LOOP;
END;
$$;

SELECT * FROM pg_temp.broki_export_legacy_raw();

